#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *arr = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&arr[i]);
        int *st = (int*)malloc(N*sizeof(int));
        int top=-1;
        for(int i=0;i<N;i++){
            int a=arr[i];
            int alive=1;
            while(alive && a<0 && top>=0 && st[top]>0){
                if(st[top] < -a){
                    top--; // top explodes
                }else if(st[top] == -a){
                    top--; // both explode
                    alive=0;
                }else{
                    alive=0; // a explodes
                }
            }
            if(alive) st[++top]=a;
        }
        if(top==-1){
            printf("\n");
        }else{
            for(int i=0;i<=top;i++){
                if(i) printf(" ");
                printf("%d",st[i]);
            }
            printf("\n");
        }
        free(arr); free(st);
    }
    return 0;
}

