import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        stack = []
        for _ in range(N):
            a = int(next(it))
            while stack and a < 0 < stack[-1]:
                if stack[-1] < -a:
                    stack.pop()
                    continue
                elif stack[-1] == -a:
                    stack.pop()
                break
            else:
                stack.append(a)
        out_lines.append(' '.join(map(str, stack)))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

